import { isPro } from '../license/LicenseValidator.js';

export class ContextMenuPlugin {
    readonly name = 'contextmenu';
    private _core: any = null;
    private _menu: HTMLElement | null = null;
    private _currentCtx: any = null;
    private _onCtxMenu = (e: MouseEvent) => this._handleContextMenu(e);
    private _onHide = () => this._hideMenu();
    private _onKeydown = (e: KeyboardEvent) => { if (e.key === 'Escape') this._hideMenu(); };

    // ── Lifecycle ────────────────────────────────────────────────────────────

    init(core: any): void {
        this._core = core;
        if (!isPro(core.settings.licenseKey)) {
            console.warn('[ContextMenuPlugin] A valid PRO licenseKey is required — plugin disabled.');
            return;
        }
        this._createMenuEl();
        const svg = core.schedulerSVGElement;
        if (svg) svg.addEventListener('contextmenu', this._onCtxMenu);
        document.addEventListener('click', this._onHide);
        document.addEventListener('keydown', this._onKeydown);
        window.addEventListener('resize', this._onHide);
        window.addEventListener('scroll', this._onHide, true);
    }

    destroy(): void {
        const svg = this._core?.schedulerSVGElement;
        if (svg) svg.removeEventListener('contextmenu', this._onCtxMenu);
        document.removeEventListener('click', this._onHide);
        document.removeEventListener('keydown', this._onKeydown);
        window.removeEventListener('resize', this._onHide);
        window.removeEventListener('scroll', this._onHide, true);
        this._menu?.remove();
        this._menu = null;
        this._core = null;
    }

    // ── Menu DOM helpers ─────────────────────────────────────────────────────

    private _createMenuEl(): void {
        const el = document.createElement('div');
        el.className = 'dropdown-menu schedula-ctx-menu';
        el.addEventListener('contextmenu', (e) => e.preventDefault());
        document.body.appendChild(el);
        this._menu = el;
    }

    private _showMenu(x: number, y: number): void {
        const menu = this._menu!;
        menu.style.display = 'block';
        menu.style.left = '0px';
        menu.style.top = '0px';
        const { width, height } = menu.getBoundingClientRect();
        const vw = window.innerWidth;
        const vh = window.innerHeight;
        let px = x;
        let py = y;
        if (px + width > vw - 6) px = vw - width - 6;
        if (py + height > vh - 6) py = vh - height - 6;
        if (px < 6) px = 6;
        if (py < 6) py = 6;
        menu.style.left = `${px}px`;
        menu.style.top = `${py}px`;
    }

    private _hideMenu(): void {
        if (!this._menu) return;
        this._menu.style.display = 'none';
        this._menu.innerHTML = '';
        this._currentCtx = null;
    }

    private _addItem(label: string, onClick: (() => void) | null, disabled = false): void {
        const a = document.createElement('a');
        a.href = '#';
        a.className = 'dropdown-item';
        a.textContent = label;
        if (disabled) {
            a.classList.add('disabled');
            a.setAttribute('aria-disabled', 'true');
            a.tabIndex = -1;
        } else if (onClick) {
            a.addEventListener('click', (e) => {
                e.preventDefault();
                e.stopPropagation();
                onClick();
                this._hideMenu();
            });
        }
        this._menu!.appendChild(a);
    }

    private _addDivider(): void {
        const hr = document.createElement('hr');
        hr.className = 'dropdown-divider';
        this._menu!.appendChild(hr);
    }

    // ── Context detection ────────────────────────────────────────────────────

    private _getContext(e: MouseEvent): any {
        const target = e.target as HTMLElement;
        const taskEl = target.closest('svg.svg-item') as HTMLElement | null;
        if (taskEl?.dataset.id) {
            return { type: 'task', date: '', taskId: taskEl.dataset.id, taskRef: taskEl.dataset.ref, taskKey: taskEl.dataset.key };
        }
        const dayunit = target.closest('rect.time-unit') as HTMLElement | null;
        if (dayunit?.dataset.date) {
            return { type: 'day', date: dayunit.dataset.date };
        }
        const cell = (target.closest('rect.box-element') ?? target.closest('rect.box-element-empty')) as HTMLElement | null;
        if (cell?.dataset.date) {
            return { type: 'cell', date: cell.dataset.date, resourceId: cell.dataset.res };
        }
        const dayCell = target.closest('rect.daybox-element') as HTMLElement | null;
        if (dayCell?.dataset.date) {
            const core = this._core;
            const resIndex = Math.floor((e.offsetY - core.headerHeight) / core.settings.resourceHeight);
            const resourceId = resIndex >= 0 && resIndex < core.data.Resources.length ? String(resIndex) : undefined;
            return { type: 'cell', date: dayCell.dataset.date, resourceId };
        }
        return null;
    }

    // ── Action dispatch ──────────────────────────────────────────────────────

    private _dispatch(ctx: any, actionName: string, description: string, capacity: number, classes: string): void {
        const isDelete = actionName === 'Elimina';
        const detail = ctx.type === 'task'
            ? { action: actionName, TaskId: ctx.taskId, TaskRef: ctx.taskRef, TaskKey: ctx.taskKey }
            : { DateFrom: ctx.date, DateTo: ctx.date, Name: isDelete ? '' : actionName, Description: description, Capacity: capacity, Classes: classes, ResourceId: ctx.resourceId ? parseInt(ctx.resourceId, 10) : null, isDelete };
        const eventName = ctx.type === 'task' ? 'schedulatask:action' : 'schedulacalendar:action';
        const svg = this._core?.schedulerSVGElement;
        svg?.dispatchEvent(new CustomEvent(eventName, { bubbles: true, detail }));
    }

    // ── Context menu event handler ───────────────────────────────────────────

    private _handleContextMenu(e: MouseEvent): void {
        const ctx = this._getContext(e);
        if (!ctx) return;
        e.preventDefault();
        this._currentCtx = ctx;
        this._buildMenu(ctx);
        if (this._menu!.children.length > 0) {
            this._showMenu(e.clientX, e.clientY);
        } else {
            this._hideMenu();
        }
    }

    // ── Menu building ────────────────────────────────────────────────────────

    private _findItem(taskId: string): any {
        for (const res of this._core?.data?.Resources ?? []) {
            const item = res.Items?.find((i: any) => i.Id == taskId);
            if (item) return item;
        }
        return null;
    }

    private _getPopupProvider(): any {
        if (this._core?.settings?.popupProvider) return this._core.settings.popupProvider;
        for (const p of this._core?.settings?.plugins ?? []) {
            if (typeof p.show === 'function') return p;
        }
        return null;
    }

    private _buildMenu(ctx: any): void {
        this._menu!.innerHTML = '';
        const ro = this._core?.settings.canMoveItems === false;
        if (ctx.type === 'task') {
            this._addItem('Modifica', () => {
                const item = this._findItem(ctx.taskId);
                const provider = this._getPopupProvider();
                if (!item || !provider) return;
                const existingPopup = document.querySelector('.scheduler-popup');
                const isVisible = existingPopup && (existingPopup as HTMLElement).style.display !== 'none';
                if (isVisible && typeof provider.refreshItem === 'function') {
                    provider.refreshItem(item);
                } else {
                    const rect = this._menu!.getBoundingClientRect();
                    const fakeEvent = new MouseEvent('click', { clientX: rect.left, clientY: rect.top, bubbles: true });
                    provider.show(item, fakeEvent, this._core);
                }
            }, ro);
            this._addDivider();
            this._addItem('Elimina', () => {
                if (!confirm('Confermi di voler eliminare questo task?')) return;
                const item = this._findItem(ctx.taskId);
                if (item) { item.Deleted = true; item.Modified = true; }
                document.querySelector(`svg[data-id="${ctx.taskId}"]`)?.remove();
                if (typeof (window as any).modified === 'function') (window as any).modified();
            }, ro);
            return;
        }
        if (ctx.type === 'day') {
            this._addItem('Festivo', () => this._withConfirm('Festivo', () => this._dispatch(ctx, 'Festivo', 'Chiusura festiva', 0, 'timeoff')), ro);
            this._addItem('Chiuso', () => this._withConfirm('Chiuso', () => this._dispatch(ctx, 'Chiuso', 'Chiusura', 0, 'closed')), ro);
            this._addItem('Manutenzione', () => this._withConfirm('Manutenzione', () => this._dispatch(ctx, 'Manutenzione', 'Manutenzione', 0, 'maintenance')), ro);
            this._addDivider();
            this._addItem('8 ore', () => this._withConfirm('8 ore', () => this._dispatch(ctx, '8 ore', 'Capacità 8 ore', 480, 'cap8h')), ro);
            this._addItem('16 ore', () => this._withConfirm('16 ore', () => this._dispatch(ctx, '16 ore', 'Capacità 16 ore', 960, 'cap16h')), ro);
            this._addItem('24 ore', () => this._withConfirm('24 ore', () => this._dispatch(ctx, '24 ore', 'Capacità 24 ore', 1440, 'cap24h')), ro);
            this._addItem('Ore custom...', () => this._promptCustomHours(ctx), ro);
            this._addDivider();
            this._addItem('Elimina regola', () => {
                if (confirm('Confermi di voler ripristinare questo giorno?'))
                    this._dispatch(ctx, 'Elimina', '', 0, '');
            }, ro);
            return;
        }
        if (ctx.type === 'cell') {
            this._addItem('Non disponibile', () => this._withConfirm('Non disponibile', () => this._dispatch(ctx, 'Non disponibile', 'Risorsa non disponibile', 0, 'closed')), ro);
            this._addItem('Assenza', () => this._withConfirm('Assenza', () => this._dispatch(ctx, 'Assenza', 'Assenza risorsa', 0, 'closed')), ro);
            this._addItem('Ferie', () => this._withConfirm('Ferie', () => this._dispatch(ctx, 'Ferie', 'Ferie risorsa', 0, 'absent')), ro);
            this._addItem('Manutenzione', () => this._withConfirm('Manutenzione', () => this._dispatch(ctx, 'Manutenzione', 'Manutenzione', 0, 'maintenance')), ro);
            this._addDivider();
            this._addItem('8 ore', () => this._withConfirm('8 ore', () => this._dispatch(ctx, '8 ore', 'Capacità 8 ore', 480, 'cap8h')), ro);
            this._addItem('16 ore', () => this._withConfirm('16 ore', () => this._dispatch(ctx, '16 ore', 'Capacità 16 ore', 960, 'cap16h')), ro);
            this._addItem('24 ore', () => this._withConfirm('24 ore', () => this._dispatch(ctx, '24 ore', 'Capacità 24 ore', 1440, 'cap24h')), ro);
            this._addItem('Ore custom...', () => this._promptCustomHours(ctx), ro);
            this._addDivider();
            this._addItem('Elimina regola', () => {
                if (confirm('Confermi di voler ripristinare questa risorsa per il giorno selezionato?'))
                    this._dispatch(ctx, 'Elimina', '', 0, '');
            }, ro);
        }
    }

    // ── Small UX helpers ─────────────────────────────────────────────────────

    private _withConfirm(name: string, action: () => void): void {
        if (confirm(`Confermi di voler impostare "${name}"?`)) action();
    }

    private _promptCustomHours(ctx: any): void {
        const raw = prompt('Ore di capacità (es. 5 o 5.5):', '');
        if (raw === null) return;
        const hours = parseFloat(raw.replace(',', '.'));
        if (isNaN(hours) || hours < 0 || hours > 24) {
            alert('Valore non valido. Inserisci un numero tra 0 e 24.');
            return;
        }
        const name = `${hours} ore`;
        if (confirm(`Confermi di voler impostare "${name}"?`)) {
            this._dispatch(ctx, name, 'Capacità custom', Math.round(hours * 60), 'cap-custom');
        }
    }
}
